const body = $json.body ?? $json;
const obligations = Array.isArray(body.obligations) ? body.obligations : [];
const highPriorityCount = obligations.filter((item) => ['high', 'critical'].includes(String(item.severity || '').toLowerCase())).length;
return [{
  json: {
    event_type: body.event_type ?? 'legal_obligations.detected',
    trace_id: body.trace_id ?? null,
    document_id: body.document_id ?? null,
    user_email: body.user_email ?? null,
    from_email: body.from_email ?? 'legalreview@example.com',
    ops_email: body.ops_email ?? 'reviewer@example.com',
    manager_email: body.manager_email ?? 'admin@example.com',
    filename: body.filename ?? 'Tài liệu chưa đặt tên',
    review_status: body.review_status ?? null,
    classification: body.classification ?? 'unknown',
    risk_score: Number(body.risk_score ?? 0),
    client_url: body.client_url ?? '',
    reviewer_url: body.reviewer_url ?? '',
    obligations,
    obligation_count: obligations.length,
    high_priority_count: Number(body.high_priority_count ?? highPriorityCount),
    critical_count: Number(body.critical_count ?? obligations.filter((item) => String(item.severity || '').toLowerCase() === 'critical').length),
    valid: Boolean(body.trace_id && body.document_id && body.user_email),
    has_obligations: obligations.length > 0
  }
}];

const severityLabels = { critical: 'Nghiêm trọng', high: 'Cao', medium: 'Trung bình', low: 'Thấp' };
const urgencyLabels = { overdue: 'Quá hạn', due_soon: 'Sắp đến hạn', normal: 'Đang theo dõi', no_deadline: 'Chưa có hạn cụ thể' };
const severityRank = { critical: 4, high: 3, medium: 2, low: 1 };
const urgencyRank = { overdue: 4, due_soon: 3, normal: 2, no_deadline: 1 };
const escapeHtml = (value) => String(value ?? '').replace(/[&<>"']/g, (char) => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;' }[char]));
const formatDate = (value) => value ? new Date(value).toLocaleDateString('vi-VN', { day: '2-digit', month: '2-digit', year: 'numeric' }) : 'Chưa có hạn cụ thể';
const daysText = (value) => {
  if (value === null || value === undefined || value === '') return 'Chưa tính được số ngày còn lại';
  const days = Number(value);
  if (Number.isNaN(days)) return 'Chưa tính được số ngày còn lại';
  if (days < 0) return `Quá hạn ${Math.abs(days)} ngày`;
  if (days === 0) return 'Đến hạn hôm nay';
  return `Còn ${days} ngày`;
};
const badgeColor = (severity) => ({ critical: '#8f1d1d', high: '#ad4f32', medium: '#c99d36', low: '#0f6b68' }[severity] || '#0f6b68');
const obligations = [...($json.obligations || [])].sort((left, right) => {
  const leftDate = left.due_date ? new Date(left.due_date).getTime() : Number.POSITIVE_INFINITY;
  const rightDate = right.due_date ? new Date(right.due_date).getTime() : Number.POSITIVE_INFINITY;
  if (leftDate !== rightDate) return leftDate - rightDate;
  return (severityRank[String(right.severity || '').toLowerCase()] || 0) - (severityRank[String(left.severity || '').toLowerCase()] || 0);
});
const highestSeverity = obligations.reduce((best, item) => {
  const current = String(item.severity || 'medium').toLowerCase();
  return (severityRank[current] || 0) > (severityRank[best] || 0) ? current : best;
}, 'low');
const highestUrgency = obligations.reduce((best, item) => {
  const current = String(item.urgency || 'normal').toLowerCase();
  return (urgencyRank[current] || 0) > (urgencyRank[best] || 0) ? current : best;
}, 'no_deadline');
const needsReviewer = obligations.some((item) => {
  const severity = String(item.severity || '').toLowerCase();
  const urgency = String(item.urgency || '').toLowerCase();
  return ['critical', 'high'].includes(severity) || ['overdue', 'due_soon'].includes(urgency);
});
const to = needsReviewer ? ($json.ops_email || $json.manager_email || $json.user_email) : $json.user_email;
const cc = needsReviewer && $json.manager_email && $json.manager_email !== to ? $json.manager_email : '';
const actionUrl = needsReviewer ? ($json.reviewer_url || $json.client_url) : $json.client_url;
const headline = needsReviewer ? 'Cảnh báo cam kết & mốc cần xử lý' : 'Cam kết & mốc cần theo dõi';
const obligationRows = obligations.map((obligation, index) => {
  const severity = String(obligation.severity || 'medium').toLowerCase();
  const urgency = String(obligation.urgency || 'normal').toLowerCase();
  const color = badgeColor(severity);
  return `
    <tr><td style="padding:0 0 14px;">
      <table role="presentation" width="100%" cellspacing="0" cellpadding="0" style="border:1px solid #ded8c9;border-left:5px solid ${color};border-radius:14px;background:#fffaf0;overflow:hidden;">
        <tr><td style="padding:16px 18px;">
          <div style="font-size:12px;font-weight:800;color:${color};text-transform:uppercase;letter-spacing:.04em;">Mục ${index + 1} · ${severityLabels[severity] || severity} · ${urgencyLabels[urgency] || urgency}</div>
          <h3 style="margin:8px 0 8px;font-size:18px;line-height:1.35;color:#1f2a2e;">${escapeHtml(obligation.title)}</h3>
          <p style="margin:0 0 8px;color:#667078;font-size:13px;line-height:1.55;"><strong>Bên phụ trách:</strong> ${escapeHtml(obligation.responsible_party || 'Chưa xác định rõ')} · <strong>Hạn:</strong> ${formatDate(obligation.due_date)} (${daysText(obligation.days_left)})</p>
          ${obligation.consequence ? `<p style="margin:8px 0 0;font-size:14px;line-height:1.6;color:#223136;"><strong>Rủi ro nếu bỏ sót:</strong> ${escapeHtml(obligation.consequence)}</p>` : ''}
          ${obligation.recommended_action ? `<p style="margin:8px 0 0;font-size:14px;line-height:1.6;color:#223136;"><strong>Việc nên làm:</strong> ${escapeHtml(obligation.recommended_action)}</p>` : ''}
          ${obligation.source_excerpt ? `<blockquote style="margin:12px 0 0;padding:10px 12px;border-left:3px solid #0f6b68;background:#f7fbfa;color:#344247;font-size:12px;line-height:1.55;">${escapeHtml(obligation.source_excerpt)}</blockquote>` : ''}
        </td></tr>
      </table>
    </td></tr>`;
}).join('');
const html = `
<div style="margin:0;padding:0;background:#f7f4ec;font-family:Arial,'Helvetica Neue',sans-serif;color:#223136;">
  <table role="presentation" width="100%" cellspacing="0" cellpadding="0" style="background:#f7f4ec;padding:28px 12px;">
    <tr><td align="center">
      <table role="presentation" width="720" cellspacing="0" cellpadding="0" style="max-width:720px;width:100%;background:#fffdf8;border:1px solid #ded8c9;border-radius:18px;overflow:hidden;box-shadow:0 18px 45px rgba(31,42,46,.12);">
        <tr><td style="background:#223136;padding:24px 28px;color:#fff;">
          <div style="font-size:12px;letter-spacing:.12em;text-transform:uppercase;color:#d9b45c;font-weight:800;">LegalReview AI · Workflow 3</div>
          <h1 style="margin:8px 0 0;font-family:Georgia,'Times New Roman',serif;font-size:28px;line-height:1.15;">${escapeHtml(headline)}</h1>
          <p style="margin:10px 0 0;color:#dbe3e3;font-size:14px;line-height:1.6;">AI đã bóc ${obligations.length} cam kết/mốc cần theo dõi từ tài liệu sau khi review.</p>
        </td></tr>
        <tr><td style="padding:24px 28px;">
          <div style="display:inline-block;background:${badgeColor(highestSeverity)};color:#fff;border-radius:999px;padding:7px 12px;font-size:12px;font-weight:800;">Mức cao nhất: ${severityLabels[highestSeverity] || highestSeverity} · ${urgencyLabels[highestUrgency] || highestUrgency}</div>
          <h2 style="margin:16px 0 8px;font-size:22px;line-height:1.3;color:#1f2a2e;">${escapeHtml($json.filename)}</h2>
          <p style="margin:0 0 20px;color:#667078;font-size:14px;line-height:1.6;">Điểm rủi ro tài liệu: <strong style="color:#223136;">${escapeHtml($json.risk_score)}</strong>. Email này gom tất cả cam kết/mốc trong một lần gửi để tránh spam người nhận.</p>
          <table role="presentation" width="100%" cellspacing="0" cellpadding="0">${obligationRows}</table>
          <div style="margin-top:18px;">
            <a href="${escapeHtml(actionUrl)}" style="display:inline-block;background:#0f6b68;color:#fff;text-decoration:none;border-radius:10px;padding:12px 18px;font-weight:800;">Mở tài liệu</a>
          </div>
        </td></tr>
        <tr><td style="background:#f0eadc;padding:16px 28px;color:#726b60;font-size:12px;line-height:1.5;">Email này được tạo tự động bởi n8n từ kết quả phân tích AI. Vui lòng kiểm tra lại tài liệu gốc trước khi ra quyết định pháp lý cuối cùng.</td></tr>
      </table>
    </td></tr>
  </table>
</div>`;
const text = [
  `${headline}`,
  '',
  `Tài liệu: ${$json.filename}`,
  `Số cam kết/mốc: ${obligations.length}`,
  `Mức cao nhất: ${severityLabels[highestSeverity] || highestSeverity}`,
  '',
  ...obligations.flatMap((obligation, index) => [
    `${index + 1}. ${obligation.title}`,
    `   Hạn: ${obligation.due_date || 'Chưa có'} · ${daysText(obligation.days_left)}`,
    `   Mức: ${severityLabels[String(obligation.severity || 'medium').toLowerCase()] || obligation.severity}`,
    `   Việc nên làm: ${obligation.recommended_action || 'Kiểm tra tài liệu gốc.'}`,
    '',
  ]),
  `Mở tài liệu: ${actionUrl}`,
].join('\n');
return [{
  json: {
    ...$json,
    to,
    cc,
    subject: `${needsReviewer ? '[LegalReview] Cảnh báo cam kết & mốc' : '[LegalReview] Cam kết & mốc cần theo dõi'}: ${$json.filename}`,
    html,
    text,
    email_obligation_count: obligations.length,
    highest_severity: highestSeverity,
    highest_urgency: highestUrgency,
  }
}];
